noncompliant:
void badFunction() {
    // Noncompliant: empty throw outside catch block
    if (someCondition) {
        throw;  // Will call std::terminate if no active exception
    }
}

void anotherBadFunction() {
    // Noncompliant: empty throw in normal function
    throw;  // Dangerous - no exception to re-throw
}

compliant:
void goodFunction() {
    try {
        riskyOperation();
    } catch (const std::exception& e) {
        // Compliant: empty throw in catch block
        log(e.what());
        throw;  // Re-throws the caught exception
    }
}

void properErrorHandling() {
    try {
        processData();
    } catch (const CustomError& e) {
        // Compliant: partial handling then re-throw
        cleanup();
        throw;  // Passes exception to higher level
    }
}
